import assert from 'node:assert/strict'
import { test } from 'node:test'
import { max, mean, min, sum } from '../src/stats.mjs'

test('sum/mean/min/max on a simple series', () => {
  const v = [4, 1, 9, 7, 3, 5]
  assert.equal(sum(v), 29)
