// Coverage gap-fill for median(): the pre-existing acceptance suite
// (test/median.test.mjs, immutable) only asserts sorting/odd-even/CLI
// behavior. It does not exercise median()'s own input validation or its
// non-mutation guarantee (both explicit requirements in task.md). Those two
// behaviors are median-specific (median is the only stat that copies/sorts
// its input) and are not asserted anywhere else in the test/ suite that
// `npm test` runs, so they are added here rather than duplicating
// test/stats.test.mjs (which only exercises validation via mean()/min()).

import assert from 'node:assert/strict'
import { test } from 'node:test'
import { median } from '../src/stats.mjs'

test('median() rejects empty input and non-numbers', () => {
  assert.throws(() => median([]), /non-empty/)
  assert.throws(() => median(['x']), /not a finite number/)
})

test('median() does not mutate its input array', () => {
  const input = [3, 1, 2]
  const result = median(input)
  assert.equal(result, 2)
  assert.deepEqual(input, [3, 1, 2])
})

